#include <stdio.h>

void moveZeroes(int* arr, int arrSize) {
    int* write = arr;
    for (int read = 0; read < arrSize; read++) {
        if (*(arr + read) != 0) {
            *write = *(arr + read);
            write++;
        }
    }
    while (write < arr + arrSize) {
        *write = 0;
        write++;
    }
}

int main() {
    int arr[] = {0, 1, 0, 3, 12};
    int arrSize = sizeof(arr) / sizeof(arr[0]);
    moveZeroes(arr, arrSize);
    for (int i = 0; i < arrSize; i++) {
        printf("%d ", arr[i]);
    }
    return 0;
}

